import React, { useState } from 'react'
import {AiOutlineClose} from 'react-icons/ai'

const Popup = (props) => {

    // const [price,setPrice]=useState({
    //     price:'0',
    //     serviceType:'',
    //     Duration:''
    // });


  return (props.trigger)?(
    <div className='bg-richblack-900/54 h-[100vh] w-full fixed top-0 left-0 flex justify-center items-center'>
        <div className='bg-richblack-900 relative w-[500px] '>
            <button className=' p-2 hover:bg-[#ec0404] absolute top-1 right-1'>
                <AiOutlineClose fontSize={17} fill='#AFB2BF' className='hover: ease-in duration-300 cursor-pointer'/>
            </button>
            <div className='flex ' >
                {/* 1month */}
                <div onClick={setPrice(1500)}>
                    <p>1 Month</p>
                    <span>₹</span>
                    <span>1500</span>
                </div>
                {/* 3month */}
                <div onClick={setPrice(4250)}>
                    <p>3 Month</p>
                    <span >₹</span>
                    <span className='line-through'>4500</span>
                    <span>4250</span>
                </div>
                {/* 6 month */}
                <div onClick={setPrice(8000)}>
                    <p>6 Month</p>
                    <span>₹</span>
                    <span className='line-through'>9000</span>
                    <span>8000</span>
                </div>
                
                <div className=''>
                    <p>Make Payment</p>
                    <p>Pay platform fee </p>
                    <span>₹</span>
                    <span>49</span>
                </div>
            </div>
        </div>
    </div>
  ):"";
}

export default Popup
